{action_set_definitions}: {
  "get_environment_snapshot": {
    "description": "Retrieves the current high-level status of the environment, including active security alerts, overall system health, and the detected stage of the threat actor.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "active_alerts": [
        {
          "alert_id": "ALRT-001",
          "source": "192.168.1.50",
          "description": "Unauthorized PLC Logic Write Attempt",
          "severity": "High"
        }
      ],
      "system_resource_health": 95,
      "threat_actor_stage": "lateral_movement"
    }
  },
  "scan_network_inventory": {
    "description": "Scans the network to identify all hosts, their IDs, roles (e.g., Historian, PLC, Workstation), and current connectivity status.",
    "parameters": {
      "type": "object",
      "properties": {
        "segment": {
          "type": "string",
          "description": "The network segment to scan (e.g., 'Level 1', 'DMZ', 'All')."
        }
      },
      "required": [
        "segment"
      ]
    },
    "example_output": {
      "hosts": [
        {
          "host_id": "HOST-HIST-01",
          "role": "Historian",
          "ip": "10.0.0.5",
          "status": "online"
        },
        {
          "host_id": "PLC-PUMP-01",
          "role": "Controller",
          "ip": "10.0.1.10",
          "status": "online"
        }
      ]
    }
  },
  "list_firewall_rules": {
    "description": "Returns the current active firewall Access Control Lists (ACLs) and traffic filtering rules.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "rules": [
        {
          "rule_id": "FW-101",
          "source": "Any",
          "destination": "Historian",
          "action": "Allow",
          "port": 443
        }
      ]
    }
  },
  "update_firewall_rule": {
    "description": "Modifies or adds a firewall rule to block or permit specific traffic. Used for isolating compromised hosts.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "ALLOW",
            "DENY"
          ],
          "description": "The action to take on the traffic."
        },
        "source_id": {
          "type": "string",
          "description": "The host ID or network range originating the traffic."
        },
        "destination_id": {
          "type": "string",
          "description": "The host ID or network range receiving the traffic."
        },
        "port": {
          "type": "string",
          "description": "The specific port or 'ALL'."
        }
      },
      "required": [
        "action",
        "source_id",
        "destination_id"
      ]
    },
    "example_output": {
      "status": "success",
      "rule_id": "FW-999"
    }
  },
  "check_plc_status": {
    "description": "Inspects a specific PLC (Programmable Logic Controller) for operational status, logic integrity hashes, and recent modification timestamps.",
    "parameters": {
      "type": "object",
      "properties": {
        "controller_id": {
          "type": "string",
          "description": "The host ID of the PLC to inspect."
        }
      },
      "required": [
        "controller_id"
      ]
    },
    "example_output": {
      "logic_integrity": "COMPROMISED",
      "last_modified": "2023-10-27T10:00:00Z",
      "operational_status": "Running"
    }
  },
  "remediate_plc_logic": {
    "description": "Restores the PLC logic to a known-good baseline and locks the configuration to prevent unauthorized changes.",
    "parameters": {
      "type": "object",
      "properties": {
        "controller_id": {
          "type": "string",
          "description": "The host ID of the PLC to remediate."
        },
        "baseline_version": {
          "type": "string",
          "description": "The version tag of the verified gold-standard logic."
        }
      },
      "required": [
        "controller_id",
        "baseline_version"
      ]
    },
    "example_output": {
      "status": "restored_and_locked",
      "controller_id": "PLC-PUMP-01"
    }
  }
}
